function activeSceneSpace(){return Scene.spaces.find(space=>space.id===Scene.activeSpace)||Scene.spaces[0]}
function enemyProfiles(){return [...(D.enemies?.common||[]),...(D.enemies?.modifiers||[])]}
function enemyProfile(id){return enemyProfiles().find(enemy=>enemy.id===id)}
function sceneSnapshot(){return sceneCore(Scene)}
function sceneEvent(text){Scene.log.unshift({id:uid(),at:new Date().toLocaleTimeString("ru-RU",{hour:"2-digit",minute:"2-digit"}),text});Scene.log=Scene.log.slice(0,80)}
function commitScene(label,mutator){const before=sceneSnapshot();mutator(Scene);Scene.undo.unshift({id:uid(),label,state:before});Scene.undo=Scene.undo.slice(0,20);sceneEvent(label);persist();renderScene();Sync?.queueScene(sceneSnapshot(),label)}
function undoScene(){const step=Scene.undo.shift();if(!step)return toast("В журнале нет обратимого действия");const remaining=Scene.undo,restored=sceneCore(step.state);restored.undo=remaining;Scene=restored;sceneEvent(`Отменено: ${step.label}`);persist();renderScene();Sync?.queueScene(sceneSnapshot(),`scene.undo:${step.label}`)}
