function abilityByKey(key){return key==="taintedAbility"?S.taintedAbility:S.ability}
function abilityPrefix(key){return key==="taintedAbility"?"tainted":"ability"}
function addAbilityWord(key,group,id){const ability=abilityByKey(key);if(id&&!ability.words[group].includes(id))ability.words[group].push(id);renderAll()}
function setAbilitySpecialization(target){const id=target.dataset.wordSpecialization;if(!id)return false;const ability=abilityByKey(target.dataset.abilityKey),value=target.value.slice(0,120);if(value.trim())ability.specializations[id]=value;else delete ability.specializations[id];return true}
$("ranks-panel").addEventListener("click",event=>{const add=event.target.closest("[data-word-add]"),custom=event.target.closest("[data-custom-word-add]"),remove=event.target.closest("[data-word-remove]");if(add){const key=add.dataset.abilityKey||"ability",group=add.dataset.wordAdd,select=$(`${abilityPrefix(key)}-word-${group}`);addAbilityWord(key,group,select?.value);return}if(custom){const key=custom.dataset.abilityKey||"ability",group=custom.dataset.customWordAdd,input=$(`${abilityPrefix(key)}-custom-${group}`),name=input?.value.trim();if(name)addAbilityWord(key,group,`custom:${group}:${encodeURIComponent(name)}`);return}if(remove){const key=remove.dataset.abilityKey||"ability",ability=abilityByKey(key),group=remove.dataset.wordGroup,id=remove.dataset.wordRemove;ability.words[group]=ability.words[group].filter(wordId=>wordId!==id);delete ability.specializations[id];renderAll()}});
$("ranks-panel").addEventListener("input",event=>{const key=event.target.dataset.abilityKey;if(!key)return;const ability=abilityByKey(key),field=event.target.dataset.abilityField;if(field==="name"||field==="desc")ability[field]=event.target.value;if(setAbilitySpecialization(event.target)){const editor=event.target.closest(".ability-grid"),total=editor?.querySelector('input[disabled]');if(total)total.value=abilityCost(ability)}renderSheet();renderSidebar();if(store.mode==="play")renderPlay();persist();});
$("ranks-panel").addEventListener("change",event=>{const key=event.target.dataset.abilityKey;if(!key)return;const ability=abilityByKey(key),group=event.target.dataset.wordSelect;if(group&&event.target.value){addAbilityWord(key,group,event.target.value);return}if(setAbilitySpecialization(event.target)){renderAll();return}const field=event.target.dataset.abilityField;if(field==="rank")ability.rank=+event.target.value;if(field==="xNoun")ability.xNoun=event.target.value||null;renderAll();});
$("rank-modifiers").addEventListener("change",event=>{if(event.target.id==="tainted-toggle"){S.mods.taintedBody=event.target.checked;S.taintedAbility.enabled=event.target.checked}if(event.target.id==="gadget-spent")S.mods.gadgetSpent=clamp(event.target.value,0,99);if(event.target.id==="performance-skill")S.mods.performanceSkill=event.target.value||null;renderAll();});
$("arch-tabs").addEventListener("click",event=>{const b=event.target.closest("[data-arch]");if(b){activeArch=b.dataset.arch;renderTechniques();}});$("tech-search").addEventListener("input",renderTechniques);
$("tech-list").addEventListener("click",event=>{const b=event.target.closest("[data-tech]");if(!b)return;const id=b.dataset.tech,level=+b.dataset.level;S.techniques[id]=(S.techniques[id]||0)===level?level-1:level;if(!S.techniques[id])delete S.techniques[id];renderAll();});
$("hero-select").onchange=e=>{store.heroes[store.current]=S;store.current=+e.target.value;S=normalizeHero(store.heroes[store.current]);pendingAllIn=null;renderAll();};
$("hero-new").onclick=()=>{store.heroes.push(blankHero());store.current=store.heroes.length-1;S=store.heroes[store.current];pendingAllIn=null;renderAll();};
$("hero-copy").onclick=()=>{const copy=normalizeHero(JSON.parse(JSON.stringify(S)));copy.id=uid();copy.name=(copy.name||"Безымянный")+" · копия";store.heroes.push(copy);store.current=store.heroes.length-1;S=copy;pendingAllIn=null;renderAll();};
$("hero-delete").onclick=()=>{if(store.heroes.length===1)return toast("Нельзя удалить единственного героя");if(!confirm(`Удалить «${S.name||"Безымянный"}»?`))return;store.heroes.splice(store.current,1);store.current=Math.max(0,store.current-1);S=store.heroes[store.current];pendingAllIn=null;renderAll();};
$("export-hero").onclick=()=>download(`DAWN-${(S.name||"hero").replace(/[^a-zа-я0-9_-]+/gi,"-")}.json`,JSON.stringify({format:"dawn-ru-hero",schema:APP_SCHEMA,hero:S},null,2));
$("import-hero").onchange=async event=>{const file=event.target.files[0];event.target.value="";if(!file)return;if(file.size>2_000_000)return toast("Файл слишком велик");try{const data=JSON.parse(await file.text());const raw=data?.format==="dawn-ru-hero"?data.hero:data;if(!raw||typeof raw!=="object"||Array.isArray(raw))throw new Error();const hero=normalizeHero(raw);hero.id=uid();store.heroes.push(hero);store.current=store.heroes.length-1;S=hero;pendingAllIn=null;renderAll();toast("Герой импортирован");}catch{toast("Это не поддерживаемый JSON героя");}};
$("print-sheet").onclick=()=>window.print();

function configureSyncFromForm(){if(!Sync)throw new Error("Модуль общего стола не загрузился");return Sync.configure({url:$("sync-url").value,publishableKey:$("sync-key").value,displayName:$("sync-display-name").value||S.player||"Игрок"})}
async function runSyncAction(action,success){try{await action();renderSync();renderScene();if(success)toast(success)}catch(error){renderSync();toast(error?.message||"Не удалось подключить общий стол")}}
let lastInviteToken="",pendingSceneCommands=[];
$("sync-connect").onclick=()=>runSyncAction(async()=>{configureSyncFromForm();await Sync.connect()},"Авторизация общего стола готова");
$("sync-create-campaign").onclick=()=>runSyncAction(async()=>{configureSyncFromForm();await Sync.connect();await Sync.createCampaign($("sync-campaign-name").value.trim()||"Серия DAWN",sceneSnapshot())},"Кампания создана; Сцена синхронизируется");
$("sync-join-campaign").onclick=()=>runSyncAction(async()=>{configureSyncFromForm();await Sync.connect();await Sync.redeemInvite($("sync-invite-token").value)},"Вы вошли за общий стол");
$("sync-create-invite").onclick=()=>runSyncAction(async()=>{lastInviteToken=await Sync.createInvite("player");$("sync-invite-output").textContent=`Токен игрока: ${lastInviteToken}`;$("sync-copy-invite").hidden=false},"Приглашение действует 7 дней или 8 входов");
$("sync-copy-invite").onclick=()=>runSyncAction(async()=>{if(!lastInviteToken)throw new Error("Сначала создайте приглашение");await navigator.clipboard.writeText(lastInviteToken)},"Токен скопирован");
$("sync-leave").onclick=()=>runSyncAction(async()=>{await Sync.leave();lastInviteToken="";$("sync-invite-output").textContent="";$("sync-copy-invite").hidden=true},"Компаньон снова работает локально");
$("sync-send-targets").onclick=()=>runSyncAction(async()=>{await Sync.submitCommand("set_targets",{targetIds:Scene.targetIds.slice(0,40),heroId:S.id})},"Цели отправлены Нарратору на подтверждение");
$("sync-request-undo").onclick=()=>runSyncAction(async()=>{await Sync.submitCommand("request_undo",{reason:"player_request"})},"Запрос отката отправлен Нарратору");
$("sync-command-queue").addEventListener("click",event=>{const button=event.target.closest("[data-sync-command]");if(!button)return;runSyncAction(async()=>{const command=pendingSceneCommands.find(item=>String(item.id)===button.dataset.syncCommand);if(!command)return;let decision=button.dataset.syncDecision;if(decision==="applied"&&command.command_type==="set_targets"){const ids=Array.isArray(command.payload?.targetIds)?command.payload.targetIds:[],allowed=new Set(Scene.actors.map(actor=>actor.id));commitScene("Нарратор принял цели игрока",scene=>{scene.targetIds=ids.filter(id=>typeof id==="string"&&allowed.has(id)).slice(0,40)})}else if(decision==="applied"&&command.command_type==="request_undo")undoScene();else if(decision==="applied")decision="rejected";await Sync.decideCommand(command.id,decision);pendingSceneCommands=pendingSceneCommands.filter(item=>String(item.id)!==String(command.id));renderSync()},"Команда игрока обработана")});

Sync?.on("status",()=>{renderSync();if(store.mode==="play")renderScene()});
Sync?.on("scene",payload=>{if(!payload?.state||typeof payload.state!=="object")return;Scene=normalizeScene(payload.state);store.scene=Scene;persist();if(store.mode==="play")renderPlay()});
Sync?.on("commands",commands=>{pendingSceneCommands=Array.isArray(commands)?commands:[];renderSync()});
Sync?.on("command",command=>{if(command&&!pendingSceneCommands.some(item=>String(item.id)===String(command.id)))pendingSceneCommands.push(command);renderSync();toast(`Получена команда игрока: ${command.command_type}`)});

$("scene-view").addEventListener("change",event=>{Scene.view=event.target.value==="player"?"player":"gm";persist();renderScene()});
$("scene-workbench").addEventListener("click",event=>{const template=event.target.closest("[data-scene-template]");if(template){applySceneTemplate(+template.dataset.sceneTemplate);return}const tool=event.target.closest("[data-scene-tool]");if(tool){Scene.tool=tool.dataset.sceneTool;scenePreviewCells.clear();persist();renderScene();return}const space=event.target.closest("[data-scene-space]");if(space){Scene.activeSpace=space.dataset.sceneSpace;Scene.selectedActor=null;Scene.targetIds=[];persist();renderScene()}});
$("scene-board").addEventListener("click",event=>{const actorButton=event.target.closest("[data-scene-actor]"),markerButton=event.target.closest("[data-scene-marker]"),cell=event.target.closest("[data-scene-cell]");if(!cell)return;const [x,y]=cell.dataset.sceneCell.split(",").map(Number),actor=actorButton&&Scene.actors.find(item=>item.id===actorButton.dataset.sceneActor),clickedMarker=markerButton&&Scene.markers.find(item=>item.id===markerButton.dataset.sceneMarker);
  if(Scene.tool==="area"){const space=activeSceneSpace(),shape=$("scene-area-shape").value,cells=Logic.areaCells({shape,x,y,width:space.width,height:space.height}),type=$("scene-area-type").value,source=$("scene-area-source").value||"Ручное правило",duration=$("scene-area-duration").value,label=$("scene-area-label").value.trim()||SCENE_TYPE_NAMES[type];commitScene(`Размещено «${label}» (${cells.length} кл.)`,scene=>{scene.objects.push({id:uid(),space:scene.activeSpace,type,label,source,duration,ownerActorId:scene.selectedActor,cells,createdRound:scene.round});scene.targetIds=scene.actors.filter(item=>item.space===scene.activeSpace&&cells.includes(`${item.x},${item.y}`)).map(item=>item.id)});return}
  if(Scene.tool==="marker"){const kind=$("scene-marker-kind").value,source=$("scene-marker-source").value||"Ручное правило",duration=$("scene-marker-duration").value,label=$("scene-marker-label").value.trim()||SCENE_MARKERS[kind].name,color=safeColor($("scene-marker-color").value,"#e2b54a");commitScene(`Поставлен маркер «${label}»`,scene=>{scene.markers.push({id:uid(),space:scene.activeSpace,x,y,kind,label,color,source,duration,ownerActorId:scene.selectedActor,createdRound:scene.round})});return}
  if(Scene.tool==="erase"&&clickedMarker){commitScene(`Удалён маркер «${clickedMarker.label}»`,scene=>{scene.markers=scene.markers.filter(item=>item.id!==clickedMarker.id)});return}
  if(actor){if(Scene.tool==="erase"){commitScene(`Убран участник «${actor.name}»`,scene=>{scene.actors=scene.actors.filter(item=>item.id!==actor.id);scene.targetIds=scene.targetIds.filter(id=>id!==actor.id);if(scene.selectedActor===actor.id)scene.selectedActor=null});return}if(Scene.tool==="target"){Scene.targetIds=Scene.targetIds.includes(actor.id)?Scene.targetIds.filter(id=>id!==actor.id):Scene.targetIds.concat(actor.id);persist();renderScene();return}Scene.selectedActor=actor.id;persist();renderScene();return}
  if(Scene.tool==="erase"){const object=[...Scene.objects].reverse().find(item=>item.space===Scene.activeSpace&&item.cells.includes(`${x},${y}`));if(object)commitScene(`Удалена область «${object.label}»`,scene=>{scene.objects=scene.objects.filter(item=>item.id!==object.id)});return}
  if(Scene.tool==="select"&&Scene.selectedActor){const moving=Scene.actors.find(item=>item.id===Scene.selectedActor);if(moving)commitScene(`«${moving.name}»: ${String.fromCharCode(65+moving.x)}${moving.y+1} → ${String.fromCharCode(65+x)}${y+1}`,()=>{moving.x=x;moving.y=y})}
});
$("scene-board").addEventListener("mouseover",event=>{const cell=event.target.closest("[data-scene-cell]");if(!cell||Scene.tool!=="area")return;const [x,y]=cell.dataset.sceneCell.split(",").map(Number),space=activeSceneSpace();scenePreviewCells=new Set(Logic.areaCells({shape:$("scene-area-shape").value,x,y,width:space.width,height:space.height}));$$('[data-scene-cell]').forEach(item=>item.classList.toggle("preview",scenePreviewCells.has(item.dataset.sceneCell)))});
$("scene-board").addEventListener("mouseleave",()=>{scenePreviewCells.clear();$$('[data-scene-cell].preview').forEach(item=>item.classList.remove("preview"))});
$("scene-area-shape").addEventListener("change",()=>{scenePreviewCells.clear()});
$("scene-clear-targets").onclick=()=>{Scene.targetIds=[];persist();renderScene()};$("scene-undo").onclick=undoScene;
$("scene-add-hero").onclick=()=>{
  const heroId=$("scene-hero-select").value,index=store.heroes.findIndex(hero=>hero.id===heroId),hero=store.heroes[index];if(!hero)return toast("Выберите героя из билдера");store.current=index;S=hero;ensureRuntime();renderHeroSelect();renderProfile();renderSidebar();const d=derivedFor(hero),existing=Scene.actors.find(actor=>actor.heroId===hero.id);
  if(existing){commitScene(`Обновлён герой «${hero.name||"Безымянный"}» из билдера`,()=>{existing.name=hero.name||"Безымянный герой";existing.tier=hero.tier;existing.hp=hero.runtime.hp??d.hp;existing.maxHp=d.hp;existing.speed=d.speed;existing.effects=[...hero.runtime.effects];existing.tokenImage=hero.media.token;existing.portraitImage=hero.media.portrait;Scene.activeSpace=existing.space;Scene.selectedActor=existing.id});return}
  const position=firstEmptyCell(Scene.activeSpace);commitScene(`Добавлен герой «${hero.name||"Безымянный"}»`,scene=>{const actor={id:uid(),kind:"hero",team:"hero",heroId:hero.id,profileId:null,name:hero.name||"Безымянный герой",tier:hero.tier,space:scene.activeSpace,...position,hp:hero.runtime.hp??d.hp,maxHp:d.hp,speed:d.speed,armor:0,evasion:0,effects:[...hero.runtime.effects],acted:false,hidden:false,tokenSymbol:"✦",tokenColor:"#256a92",tokenImage:hero.media.token,portraitImage:hero.media.portrait};scene.actors.push(actor);scene.selectedActor=actor.id})
};
$("scene-enemy-search").addEventListener("input",event=>{sceneEnemyFilter=event.target.value;renderEnemySelect()});
$("scene-add-enemy").onclick=()=>{const profile=enemyProfile($("scene-enemy-select").value);if(!profile)return toast("Выберите профиль врага");const tier=clamp($("scene-enemy-tier").value,1,99),stats=scaledEnemyStats(profile,tier),position=firstEmptyCell(Scene.activeSpace);commitScene(`Добавлен враг «${profile.name}» Ст.${tier}`,scene=>{const actor={id:uid(),kind:"enemy",team:"enemy",heroId:null,profileId:profile.id,name:profile.name,tier,space:scene.activeSpace,...position,hp:stats.health,maxHp:stats.health,speed:stats.speed,armor:stats.armor,evasion:stats.evasion,effects:[],acted:false,hidden:false,tokenSymbol:"☠",tokenColor:"#902a3d",tokenImage:"",portraitImage:""};scene.actors.push(actor);scene.selectedActor=actor.id})};
$("scene-add-free-token").onclick=()=>{const name=$("scene-free-token-name").value.trim()||"Свободный токен",team=$("scene-free-token-team").value==="enemy"?"enemy":"hero",position=firstEmptyCell(Scene.activeSpace);commitScene(`Добавлен токен «${name}»`,scene=>{const actor={id:uid(),kind:"token",team,heroId:null,profileId:null,name:name.slice(0,120),tier:1,space:scene.activeSpace,...position,hp:1,maxHp:1,speed:0,armor:0,evasion:0,effects:[],acted:false,hidden:false,tokenSymbol:team==="enemy"?"☠":"✦",tokenColor:team==="enemy"?"#902a3d":"#256a92",tokenImage:"",portraitImage:""};scene.actors.push(actor);scene.selectedActor=actor.id});$("scene-free-token-name").value=""};
$("scene-add-space").onclick=()=>{const name=$("scene-space-name").value.trim()||`Отдельное пространство ${Scene.spaces.length}`;commitScene(`Создано пространство «${name}»`,scene=>{const space={id:uid(),name,width:7,height:7};scene.spaces.push(space);scene.activeSpace=space.id;scene.selectedActor=null;scene.targetIds=[]});$("scene-space-name").value=""};
$("scene-clear-log").onclick=()=>{Scene.log=[];persist();renderScene()};
$("scene-inspector").addEventListener("change",async event=>{
  const actorId=event.target.dataset.sceneActorName||event.target.dataset.sceneActorHp||event.target.dataset.sceneActorSpace||event.target.dataset.sceneActorActed||event.target.dataset.sceneTokenSymbol||event.target.dataset.sceneTokenColor||event.target.dataset.sceneTokenUpload,actor=Scene.actors.find(item=>item.id===actorId);if(!actor)return;
  if(event.target.dataset.sceneActorName)commitScene(`Переименован участник «${actor.name}»`,()=>{actor.name=event.target.value.trim().slice(0,120)||actor.name});
  else if(event.target.dataset.sceneActorHp)commitScene(`Здоровье «${actor.name}»: ${actor.hp} → ${clamp(event.target.value,0,9999)}`,()=>{actor.hp=clamp(event.target.value,0,9999)});
  else if(event.target.dataset.sceneActorSpace){const targetSpace=event.target.value,position=firstEmptyCell(targetSpace),spaceName=Scene.spaces.find(space=>space.id===targetSpace)?.name||"пространство";commitScene(`«${actor.name}» перенесён: ${spaceName}`,()=>{actor.space=targetSpace;actor.x=position.x;actor.y=position.y;Scene.activeSpace=targetSpace})}
  else if(event.target.dataset.sceneActorActed)commitScene(`${actor.name}: ${event.target.checked?"Ход завершён":"Ход возвращён"}`,()=>{actor.acted=event.target.checked});
  else if(event.target.dataset.sceneTokenSymbol)commitScene(`Изменён знак токена «${actor.name}»`,()=>{actor.tokenSymbol=event.target.value.slice(0,4);actor.tokenImage=""});
  else if(event.target.dataset.sceneTokenColor)commitScene(`Изменён цвет токена «${actor.name}»`,()=>{actor.tokenColor=safeColor(event.target.value,actor.tokenColor)});
  else if(event.target.dataset.sceneTokenUpload){try{const image=await tokenImageFromFile(event.target.files?.[0]),current=Scene.actors.find(item=>item.id===actorId);if(sceneMediaSize()-(current?.tokenImage?.length||0)+image.length>1850000)throw new Error("Медиа общего стола превышают 1,85 МБ; замените или удалите старое изображение");if(current)commitScene(`Загружено изображение токена «${current.name}»`,()=>{current.tokenImage=image})}catch(error){toast(error.message||"Не удалось загрузить токен")}}
});
$("scene-inspector").addEventListener("click",event=>{const turn=event.target.closest("[data-scene-turn]"),removeActor=event.target.closest("[data-scene-remove-actor]"),removeObject=event.target.closest("[data-scene-remove-object]"),removeMarker=event.target.closest("[data-scene-remove-marker]"),clearToken=event.target.closest("[data-scene-clear-token-image]"),effect=event.target.closest("[data-scene-actor-effect]");if(turn){const actor=Scene.actors.find(item=>item.id===turn.dataset.sceneActorId);if(actor){const start=turn.dataset.sceneTurn==="start";commitScene(`${actor.name}: ${start?"начат":"завершён"} Ход`,scene=>{const current=scene.actors.find(item=>item.id===actor.id);if(current)current.acted=!start;const expiring=start?"nextTurn":"endTurn";scene.objects=scene.objects.filter(object=>!(object.duration===expiring&&object.ownerActorId===actor.id));scene.markers=scene.markers.filter(marker=>!(marker.duration===expiring&&marker.ownerActorId===actor.id))})}return}if(removeActor){const actor=Scene.actors.find(item=>item.id===removeActor.dataset.sceneRemoveActor);if(actor)commitScene(`Убран участник «${actor.name}»`,scene=>{scene.actors=scene.actors.filter(item=>item.id!==actor.id);scene.targetIds=scene.targetIds.filter(id=>id!==actor.id);scene.selectedActor=null});return}if(removeObject){const object=Scene.objects.find(item=>item.id===removeObject.dataset.sceneRemoveObject);if(object)commitScene(`Удалена область «${object.label}»`,scene=>{scene.objects=scene.objects.filter(item=>item.id!==object.id)});return}if(removeMarker){const marker=Scene.markers.find(item=>item.id===removeMarker.dataset.sceneRemoveMarker);if(marker)commitScene(`Удалён маркер «${marker.label}»`,scene=>{scene.markers=scene.markers.filter(item=>item.id!==marker.id)});return}if(clearToken){const actor=Scene.actors.find(item=>item.id===clearToken.dataset.sceneClearTokenImage);if(actor)commitScene(`Удалено изображение токена «${actor.name}»`,()=>{actor.tokenImage=""});return}if(effect){const actor=Scene.actors.find(item=>item.id===effect.dataset.sceneActorEffect),id=effect.dataset.effect;if(actor)commitScene(`${actor.name}: ${actor.effects.includes(id)?"снят":"наложен"} Эффект`,()=>{actor.effects=actor.effects.includes(id)?actor.effects.filter(item=>item!==id):actor.effects.concat(id)})}});
$("scene-inspector").addEventListener("change",async event=>{const actorId=event.target.dataset.scenePortraitUpload;if(!actorId)return;try{const image=await imageFromFile(event.target.files?.[0],{maxSide:720,maxLength:420000}),actor=Scene.actors.find(item=>item.id===actorId);if(!actor)return;if(sceneMediaSize()-(actor.portraitImage?.length||0)+image.length>1850000)throw new Error("Медиа общего стола превышают 1,85 МБ; удалите старый арт или портрет");commitScene(`Загружен портрет «${actor.name}»`,()=>{actor.portraitImage=image})}catch(error){toast(error.message||"Не удалось загрузить портрет")}});
$("scene-inspector").addEventListener("click",event=>{const button=event.target.closest("[data-scene-clear-portrait-image]");if(!button)return;const actor=Scene.actors.find(item=>item.id===button.dataset.sceneClearPortraitImage);if(actor)commitScene(`Удалён портрет «${actor.name}»`,()=>{actor.portraitImage=""})});
$("scene-media-menu").addEventListener("click",event=>{const portrait=event.target.closest("[data-scene-portrait-actor]");if(portrait){const actor=Scene.actors.find(item=>item.id===portrait.dataset.scenePortraitActor);if(actor){Scene.activeSpace=actor.space;Scene.selectedActor=actor.id;persist();renderScene()}return}const button=event.target.closest("[data-scene-art-action]");if(!button)return;const art=Scene.artworks.find(item=>item.id===button.dataset.sceneArtId);if(!art)return;const action=button.dataset.sceneArtAction;if(action==="remove")commitScene(`Удалён арт «${art.name}»`,scene=>{scene.artworks=scene.artworks.filter(item=>item.id!==art.id);if(scene.featuredArt===art.id)scene.featuredArt=null;if(scene.backgroundArt===art.id)scene.backgroundArt=null});else if(action==="feature")commitScene(`${Scene.featuredArt===art.id?"Скрыт":"Показан"} арт «${art.name}»`,scene=>{scene.featuredArt=scene.featuredArt===art.id?null:art.id});else if(action==="background")commitScene(`${Scene.backgroundArt===art.id?"Снят фон":"Установлен фон"} «${art.name}»`,scene=>{scene.backgroundArt=scene.backgroundArt===art.id?null:art.id})});
$("scene-art-upload").addEventListener("change",async event=>{try{if(Scene.artworks.length>=12)throw new Error("В Сцене можно хранить не больше 12 артов");const image=await imageFromFile(event.target.files?.[0],{maxSide:960,maxLength:520000});if(sceneMediaSize()+image.length>1850000)throw new Error("Медиа общего стола превышают 1,85 МБ; удалите старый арт или портрет");const name=$("scene-art-name").value.trim()||"Арт Сцены",kind=$("scene-art-kind").value==="background"?"background":"art";commitScene(`Загружен арт «${name}»`,scene=>{const art={id:uid(),name:name.slice(0,120),kind,image,hidden:false};scene.artworks.push(art);if(kind==="background")scene.backgroundArt=art.id;else scene.featuredArt=art.id});$("scene-art-name").value=""}catch(error){toast(error.message||"Не удалось загрузить арт")}event.target.value=""});

$("play-counters").addEventListener("click",event=>{const b=event.target.closest("[data-counter]");if(!b)return;const key=b.dataset.counter;S.runtime[key]=Math.max(0,(+S.runtime[key]||0)+(+b.dataset.delta));if(key==="stress")S.runtime[key]=Math.min(3,S.runtime[key]);persist();renderPlay();});
$("play-counters").addEventListener("change",event=>{const key=event.target.dataset.counterInput;if(key){S.runtime[key]=Math.max(0,+event.target.value||0);if(key==="stress")S.runtime[key]=Math.min(3,S.runtime[key]);persist();renderPlay();}});
$("new-round").onclick=()=>{S.runtime.ap=3;S.runtime.tension++;commitScene(`Завершён Раунд ${Scene.round}`,scene=>{scene.round++;scene.actors.forEach(actor=>actor.acted=false);scene.objects=scene.objects.filter(object=>!["instant","endTurn","round"].includes(object.duration));scene.markers=scene.markers.filter(marker=>marker.duration!=="round")});renderPlay();toast("Раунд завершён: Напряжение +1, ОД восстановлены")};
$("new-scene").onclick=()=>{const d=derived();S.runtime.hp=d.hp;S.runtime.focus=d.focus;S.runtime.ap=3;S.runtime.tension=0;S.runtime.effects=[];commitScene("Начата новая Сцена",scene=>{scene.round=1;scene.targetIds=[];scene.actors.forEach(actor=>actor.acted=false);scene.objects=scene.objects.filter(object=>object.duration==="persistent");scene.markers=scene.markers.filter(marker=>marker.duration==="persistent")});renderPlay()};
function takeWound(external){const d=derived();S.runtime.wounds++;S.runtime.hp=d.guts;if(external)S.runtime.influence++;persist();renderPlay();}
$("wound-external").onclick=()=>takeWound(true);$("wound-self").onclick=()=>takeWound(false);$("intermission").onclick=()=>{S.runtime.wounds=0;S.runtime.stress=0;persist();renderPlay();};
$("scene-notes").addEventListener("input",e=>{S.runtime.notes=e.target.value;persist();});
$("effect-tracker").addEventListener("click",event=>{const b=event.target.closest("[data-effect]");if(!b)return;const id=b.dataset.effect;S.runtime.effects=S.runtime.effects.includes(id)?S.runtime.effects.filter(x=>x!==id):S.runtime.effects.concat(id);persist();renderPlay();});
$("play-kit").addEventListener("click",event=>{const button=event.target.closest("[data-sacrifice]");if(!button)return;const id=button.dataset.sacrifice;if(S.runtime.sacrifices.includes(id))return toast("По правилу Жертвы эту цену нельзя восстановить — только заменить");S.runtime.sacrifices.push(id);persist();renderPlay()});
$("focus-mode").onclick=()=>document.body.classList.toggle("focus-mode");

$("roll-dice").onclick=rollDice;$("all-in-reroll").onclick=()=>allIn("Влияние");$("all-in-stress").onclick=()=>allIn("Стресс");$("clock-add").onclick=()=>{S.runtime.clocks.push({id:uid(),name:"Новые часы",size:6,value:0});persist();renderClocks();};
$("clocks").addEventListener("click",event=>{const remove=event.target.dataset.clockRemove;if(remove){S.runtime.clocks=S.runtime.clocks.filter(c=>c.id!==remove);persist();renderClocks();return;}const id=event.target.dataset.clock;if(id){const c=S.runtime.clocks.find(c=>c.id===id);const v=+event.target.dataset.value;c.value=c.value===v?v-1:v;persist();renderClocks();}});
$("clocks").addEventListener("input",event=>{const id=event.target.dataset.clockName;if(id){const c=S.runtime.clocks.find(c=>c.id===id);if(c)c.name=event.target.value;persist();}});
$("ref-search").addEventListener("input",renderReference);$("ref-filters").addEventListener("click",event=>{const b=event.target.closest("[data-ref-kind]");if(b){refKind=b.dataset.refKind;renderReference();}});

document.documentElement.classList.toggle("light",store.theme==="light");initCollapsibleBuildPanels();setMode(store.mode||"build");renderAll();renderSync();
if(Sync?.hasConfig())window.addEventListener("load",()=>setTimeout(()=>Sync.connect().catch(()=>renderSync()),250),{once:true});
if(location.protocol.startsWith("http")&&"serviceWorker" in navigator)navigator.serviceWorker.register("./sw.js").catch(()=>{});
